import joblibimport pandas as pdmodel = joblib.load("model_for_inference_gcp.pkl")def make_prediction(inputs):    """    Make a prediction using the trained model    """    inputs_df = pd.DataFrame(        inputs,        columns=['bid', 'ask', 'delta', 'gamma', 'theta', 'vega', 'implied_volatility']        )    predictions = model.predict(inputs_df)      return predictions